frappe.ui.form.on('Pharmaceuticals', {
    item_code: function(frm, cdt, cdn) {
        let row = locals[cdt][cdn];
        if (!row.item_code) return;

        // Fetch batches for this item
        frappe.call({
            method: 'health_sil.services.batch_selection_api.get_batches_for_item',
            args: { item_code: row.item_code },
            callback: function(r) {
                if (!r.message || r.message.length === 0) {
                    frappe.msgprint(__('No batches with stock found for {0}', [row.item_code]));
                    return;
                }

                let batches = r.message;

                // If only 1 batch, auto-select it
                if (batches.length === 1) {
                    let b = batches[0];
                    frappe.model.set_value(cdt, cdn, 'batch', b.batch_no);
                    frappe.model.set_value(cdt, cdn, 'expiry_date', b.expiry_date);
                    frappe.model.set_value(cdt, cdn, 'mrp', b.mrp_per_tablet || 0);
                    frappe.model.set_value(cdt, cdn, 'actual_mrp', b.mrp_per_strip || 0);
                    frappe.model.set_value(cdt, cdn, 'strips', b.strips || 1);
                    frappe.model.set_value(cdt, cdn, 'tablets_per_strip', b.strips || 1);
                    return;
                }

                // Multiple batches - show selection dialog
                let fields = [
                    {
                        fieldtype: 'HTML',
                        fieldname: 'batch_info',
                        options: '<p style="margin-bottom:10px;"><b>Select a batch for ' + row.item_code + ':</b></p>'
                    },
                    {
                        fieldtype: 'Table',
                        fieldname: 'batch_table',
                        cannot_add_rows: true,
                        in_place_edit: false,
                        fields: [
                            {
                                fieldname: 'batch_no',
                                fieldtype: 'Data',
                                label: 'Batch No',
                                in_list_view: 1,
                                read_only: 1,
                                columns: 3
                            },
                            {
                                fieldname: 'expiry_date',
                                fieldtype: 'Date',
                                label: 'Expiry',
                                in_list_view: 1,
                                read_only: 1,
                                columns: 2
                            },
                            {
                                fieldname: 'qty_available',
                                fieldtype: 'Float',
                                label: 'Qty (Tablets)',
                                in_list_view: 1,
                                read_only: 1,
                                columns: 2
                            },
                            {
                                fieldname: 'mrp_per_tablet',
                                fieldtype: 'Currency',
                                label: 'MRP/Tablet',
                                in_list_view: 1,
                                read_only: 1,
                                columns: 2
                            },
                            {
                                fieldname: 'mrp_per_strip',
                                fieldtype: 'Currency',
                                label: 'MRP/Strip',
                                in_list_view: 1,
                                read_only: 1,
                                columns: 2
                            }
                        ]
                    }
                ];

                let d = new frappe.ui.Dialog({
                    title: __('Select Batch for {0}', [row.item_code]),
                    fields: fields,
                    size: 'large',
                    primary_action_label: __('Select'),
                    primary_action: function() {
                        let selected = d.fields_dict.batch_table.grid.get_selected_children();
                        if (selected.length === 0) {
                            frappe.msgprint(__('Please select a batch by clicking on a row'));
                            return;
                        }
                        let sel = selected[0];
                        frappe.model.set_value(cdt, cdn, 'batch', sel.batch_no);
                        frappe.model.set_value(cdt, cdn, 'expiry_date', sel.expiry_date);
                        frappe.model.set_value(cdt, cdn, 'mrp', sel.mrp_per_tablet || 0);
                        frappe.model.set_value(cdt, cdn, 'actual_mrp', sel.mrp_per_strip || 0);
                        frappe.model.set_value(cdt, cdn, 'strips', sel.strips || 1);
                        frappe.model.set_value(cdt, cdn, 'tablets_per_strip', sel.strips || 1);
                        d.hide();
                    }
                });

                // Populate table
                batches.forEach(function(b) {
                    let row_data = d.fields_dict.batch_table.grid.add_new_row();
                    frappe.model.set_value(row_data.doctype, row_data.name, {
                        batch_no: b.batch_no,
                        expiry_date: b.expiry_date,
                        qty_available: b.qty_available,
                        mrp_per_tablet: b.mrp_per_tablet || 0,
                        mrp_per_strip: b.mrp_per_strip || 0
                    });
                });

                d.fields_dict.batch_table.grid.refresh();
                d.show();
            }
        });
    },

    batch: function(frm, cdt, cdn) {
        let row = locals[cdt][cdn];
        if (!row.batch || !row.item_code) return;

        // When batch is manually changed, fetch MRP from batch
        frappe.call({
            method: 'frappe.client.get_value',
            args: {
                doctype: 'Batch',
                filters: { name: row.batch },
                fieldname: ['custom_mrp', 'custom_mrp_per_unit', 'custom_strips', 'expiry_date']
            },
            callback: function(r) {
                if (r.message) {
                    frappe.model.set_value(cdt, cdn, 'mrp', r.message.custom_mrp_per_unit || 0);
                    frappe.model.set_value(cdt, cdn, 'actual_mrp', r.message.custom_mrp || 0);
                    frappe.model.set_value(cdt, cdn, 'expiry_date', r.message.expiry_date);
                    frappe.model.set_value(cdt, cdn, 'strips', r.message.custom_strips || 1);
                    frappe.model.set_value(cdt, cdn, 'tablets_per_strip', r.message.custom_strips || 1);
                }
            }
        });
    }
});

