frappe.ui.form.on('Lab Test', {
    onload: function(frm) {
        const params = frappe.utils.get_query_params();
        if (params.patient) frm.set_value('patient', params.patient);
        if (params.practitioner) frm.set_value('practitioner_name', params.practitioner);
        if (params.lab_test_name) frm.set_value('template', params.lab_test_name);
        if (params.laboratory_bill_ref) frm.set_value('laboratory_bill_ref', params.laboratory_bill_ref);
        if (params.source_item_code) frm.set_value('source_item_code', params.source_item_code);
    }
});

frappe.ui.form.on('Purchase Invoice Item', {
    item_code(frm, cdt, cdn) {
        let row = locals[cdt][cdn];
        if (row.item_code) {
            frappe.db.get_value('Item', row.item_code, ['valuation_rate', 'custom_mrp_per_purchase_uom'])
                .then(r => {
                    if (r && r.message) {
                        console.log(row.item_code)
                        console.log(r.message.valuation_rate)
                        console.log(r.message.custom_mrp_per_purchase_uom)
                        frappe.model.set_value(cdt, cdn, 'custom_valuation_rate', r.message.valuation_rate);
                        frappe.model.set_value(cdt, cdn, 'custom_mrp', r.message.custom_mrp_per_purchase_uom);
                    }
                });
        }
    }
});

frappe.ui.form.on('Purchase Invoice', {
    on_submit: function(frm) {
        // Ensure the document is submitted
        if (frm.doc.docstatus === 1) {
            // Freeze the screen with a message
            frappe.dom.freeze(__("Creating Stock Entries..."));

            // Call the server-side method to create stock entries
            frappe.call({
                method: 'health_sil.services.purchase_invoice.create_stock_entry_from_purchase_invoice',
                args: {
                    purchase_invoice: frm.doc.name
                },
                callback: function(response) {
                    // Unfreeze the screen
                    frappe.dom.unfreeze();

                    if (response.message) {
                        frappe.msgprint({
                            title: __('Success'),
                            message: __('Stock Entries Created Successfully'),
                            indicator: 'green'
                        });
                    }
                },
                error: function(err) {
                    // Unfreeze the screen on error
                    frappe.dom.unfreeze();
                    frappe.msgprint({
                        title: __('Error'),
                        message: __('An error occurred while creating Stock Entries: {0}', [err.message]),
                        indicator: 'red'
                    });
                }
            });
        }
    }
});

frappe.ui.form.on('Patient', {
    mobile: function(frm) {
        if (!frm.doc.mobile) return;

        frappe.call({
            method: 'frappe.client.get_list',
            args: {
                doctype: 'Patient',
                filters: { 'mobile': frm.doc.mobile },
                fields: ['name', 'patient_name', 'mobile', 'uid']
            },
            callback: function(response) {
                if (response.message.length > 0) {
                    let table_html = `
                        <div class="panel panel-default" style="max-width: 800px; margin: auto;">
                          <div class="panel-body">
                            <div class="table-responsive">
                              <table class="table table-bordered table-striped table-hover">
                                  <thead style="background-color:#f8f9fa;">
                                      <tr>
                                          <th>UID</th>
                                          <th>Patient Name</th>
                                          <th>Mobile</th>
                                      </tr>
                                  </thead>
                                  <tbody>
                    `;

                    // Sort by UID in ascending order for improved readability
                    response.message.sort((a, b) => a.uid - b.uid).forEach(patient => {
                        table_html += `
                              <tr>
                                  <td>${patient.uid}</td>
                                  <td><a href="/app/patient/${patient.name}" style="color:#007bff; text-decoration:underline;">${patient.patient_name}</a></td>
                                  <td>${patient.mobile}</td>
                              </tr>
                        `;
                    });

                    table_html += `
                                  </tbody>
                              </table>
                            </div>
                          </div>
                        </div>
                    `;

                    // Display the panel in a message print
                    frappe.msgprint({
                        title: __('Duplicate Patients List'),
                        message: table_html,
                        indicator: 'red'
                    });
                }
            }
        });
    },
        refresh: function(frm) {
        // if (frm.doc.custom_free_consultation_period) {
        //     calculate_valid_till(frm);
        // }
        let consultation_valid_date = frm.doc.custom_consultation_valid_date;
        console.log(consultation_valid_date);
        let validTillDate = new Date(consultation_valid_date);
        if (consultation_valid_date){
            // Format the valid till date for display
            let formattedDate = validTillDate.toLocaleDateString('en-US', {
                year: 'numeric',
                month: 'long',
                day: 'numeric'
            });

            // Set the hidden field value in "YYYY-MM-DD" format
            let formattedHiddenDate = validTillDate.toISOString().split('T')[0];
            frm.set_value('custom_consultation_valid_date', formattedHiddenDate);
            frm.refresh_field('custom_consultation_valid_date');

            // Compare the valid till date with the form open date (current date)
            let currentDate = new Date();
            if (validTillDate < currentDate) {
                // If expired, display the message in red
                frm.fields_dict.custom_valid_till.$wrapper.html(
                    `<span style="color:red;">Consultation Expired on: ${formattedDate}</span>`
                );
                // Show an alert on the bottom right that the consultation has expired
                frappe.show_alert({
                    message: `Consultation expired on: ${formattedDate}`,
                    indicator: 'red'
                }, 5);
            } else {
                // Otherwise, display normally
                frm.fields_dict.custom_valid_till.$wrapper.html(
                    `Consultation Valid Till: ${formattedDate}`
                );
            }
            frm.refresh_field('custom_valid_till');
        } else {
            // Clear fields if no consultation period is provided
            frm.set_value('custom_consultation_valid_date', null);
            frm.refresh_field('custom_consultation_valid_date');
            frm.fields_dict.custom_valid_till.$wrapper.html("");
            frm.refresh_field('custom_valid_till');
        }
    }
});

frappe.ui.form.on('Patient', {
    // Form lifecycle events
    on_load: function(frm) {
        // Clear the cache and refresh
        frappe.clear_cache();
        frm.refresh();
        console.log("Cache cleared and form refreshed on load");
    },

    first_name(frm) {
        frm.set_value('first_name', capitalizeWords(frm.doc.first_name));
    },

    middle_name(frm) {
        frm.set_value('middle_name', capitalizeWords(frm.doc.middle_name));
    },

    last_name(frm) {
        frm.set_value('last_name', capitalizeWords(frm.doc.last_name));
    },

    refresh: function(frm) {
        console.log("Patient form refresh function executing");
        frm.dialog_shown_in_current_session = false;
        console.log("refreshing.....");

        // Hide specific buttons
        $('button:contains("Invoice Patient Registration")').each(function() {
            if ($(this).text().trim() === "Invoice Patient Registration") {
                $(this).hide();
            }
        });

        $('button:contains("ABDM")').each(function() {
            if ($(this).text().trim() === "ABDM") {
                $(this).hide();
            }
        });

        // Add the Generate Invoice button - this part is separate from the above logic
        if (!frm.is_new()) {
            console.log("Adding Generate Invoice button");
            // Add the button once (it's re-added on each refresh by Frappe anyway)
            frm.add_custom_button('Generate Invoice', function() {
                frm.refresh();
                console.log("Cache cleared custom button");
                generateInvoiceHandler(frm);
            });

            // Only auto-open the dialog for non-registered patients on form load
            // and only if a dialog isn't already showing
            if (!frm.doc.custom_is_registered && !frm.dialog_shown_in_current_session) {
                // Set this flag to prevent multiple dialogs in one session
                frm.dialog_shown_in_current_session = true;

                // Use a slight delay to ensure the UI is fully loaded
                setTimeout(() => {
                    // Check again to make sure no other process has shown the dialog
                    if (!window.current_patient_dialog_active) {
                        generateInvoiceHandler(frm);
                    }
                }, 300);
            }
        }
    },

    after_save: function(frm) {
        // Show invoice dialog only once after initial save
        // This ensures it's shown only after the first save of a new patient
        if (frm.doc.__islocal) {
            // We use setTimeout to ensure this runs after the save is complete
            // and the __islocal flag is updated
            setTimeout(() => {
                if (!frm.doc.custom_is_registered) {
                    frappe.clear_cache();
                    console.log("Cache cleared after save");
                    generateInvoiceHandler(frm);
                }
            }, 200);
        }
    },

    // Field change events
    territory: function(frm) {
        if (frm.doc.territory == "Foreign") {
            frm.set_value('default_price_list', "Foreign Price List");
        } else {
            frm.set_value('default_price_list', "Native Price List");
        }
    },

    mobile: function(frm) {
        if (!frm.doc.mobile) return;

        frappe.call({
            method: 'frappe.client.get_list',
            args: {
                doctype: 'Patient',
                filters: { 'mobile': frm.doc.mobile },
                fields: ['name', 'patient_name', 'mobile', 'uid']
            },
            callback: function(response) {
                if (response.message.length > 0) {
                    let table_html = `
                        <div class="panel panel-default" style="max-width: 800px; margin: auto;">
                            <div class="panel-body">
                                <div class="table-responsive">
                                    <table class="table table-bordered table-striped table-hover">
                                        <thead style="background-color:#f8f9fa;">
                                            <tr>
                                                <th>UID</th>
                                                <th>Patient Name</th>
                                                <th>Mobile</th>
                                            </tr>
                                        </thead>
                                        <tbody>
                    `;

                    // Sort by UID in ascending order for improved readability
                    response.message.sort((a, b) => a.uid - b.uid).forEach(patient => {
                        table_html += `
                            <tr>
                                <td>${patient.uid}</td>
                                <td><a href="/app/patient/${patient.name}" style="color:#007bff; text-decoration:underline;">${patient.patient_name}</a></td>
                                <td>${patient.mobile}</td>
                            </tr>
                        `;
                    });

                    table_html += `
                                        </tbody>
                                    </table>
                                </div>
                            </div>
                        </div>
                    `;

                    // Display the panel in a message print
                    frappe.msgprint({
                        title: __('Duplicate Patients List'),
                        message: table_html,
                        indicator: 'red'
                    });
                }
            }
        });
    }
});

// Helper functions

//capitalizing each word in names
function capitalizeWords(str) {
    if (!str) return '';
    return str
        .split(' ')
        .map(word => word.charAt(0).toUpperCase() + word.slice(1).toLowerCase())
        .join(' ');
}

// Define generateInvoiceHandler function at the global scope
function generateInvoiceHandler(frm) {
    // Prevent multiple dialogs from being shown simultaneously
    if (window.current_patient_dialog_active) {
        console.log("Dialog already active, not showing another one");
        return;
    }

    // Set global flag that we're showing a dialog
    window.current_patient_dialog_active = true;

    let patient_territory = frm.doc.territory;
    let is_registered = frm.doc.custom_is_registered;

    // If patient is already registered, we should disable registration_only option
    let enable_registration_only = !is_registered;
    let registration_fee = 0;
    let today = new Date(frappe.datetime.get_today());
    let cached_token = null;

    let dialog = new frappe.ui.Dialog({
        title: 'Generate Invoice',
        fields: [
            {
                fieldtype: 'Section Break',
                label: 'Patient Details'
            },
            {
                fieldtype: 'Data',
                fieldname: 'patient_name',
                label: 'Patient Name',
                default: frm.doc.patient_name,
                read_only: 1
            },
            {
                fieldtype: 'Column Break'
            },
            {
                fieldtype: 'Data',
                fieldname: 'registration_period',
                label: 'Registration Period',
                default: frm.doc.custom_registration_period,
                read_only: 1
            },
            {
                fieldtype: 'Section Break',
                label: 'Invoice Details'
            },
            {
                fieldtype: 'Link',
                fieldname: 'doctor_name',
                label: 'Doctor Name',
                reqd: 1, // Makes this field mandatory
                options: 'Healthcare Practitioner',
                change: function() {
                    let doctor = dialog.get_value('doctor_name');
                    if (doctor) {
                        // Check if consultation is valid for this doctor
                        checkConsultationValidity(frm, doctor, dialog);

                        frappe.call({
                            method: 'frappe.client.get',
                            args: {
                                doctype: 'Healthcare Practitioner',
                                name: doctor
                            },
                            callback: function(r) {
                                if (r.message) {
                                    // logic here
                                    console.log("patient", patient_territory);
                                    let consultation_territory_find = r.message.custom_consultation_fee_structure.find(c => c.consultation_territory === patient_territory);
                                    let consultation_territory_amt = consultation_territory_find ? consultation_territory_find.consultation_fee : null;

                                    let consultation_fee = parseFloat(consultation_territory_amt || 0);
                                    dialog.set_value('consultation_charge', consultation_fee);
                                    updateTable(dialog, parseFloat(dialog.registration_fee || 0), consultation_fee, is_registered, frm, doctor);
                                }
                            }
                        });

                        frappe.call({
                            method: 'health_sil.services.appointment_api.manage_token',
                            args: {
                                practitioner_name: doctor
                            },
                            callback: function(r) {
                                if (r.message) {
                                    cached_token = r.message;
                                    dialog.set_value('token_number', r.message);
                                }
                            }
                        });
                    }
                }
            },
            {
                fieldtype: 'Data',
                fieldname: 'consultation_charge',
                label: 'Consultation Charge',
                read_only: 1
            },
            {
                fieldtype: 'HTML',
                fieldname: 'consultation_validity_info',
                label: 'Consultation Validity'
            },
            {
                fieldtype: 'Column Break'
            },
            {
                fieldtype: 'Data',
                fieldname: 'token_number',
                label: 'Token Number'
            },
            {
                fieldtype: 'Link',
                fieldname: 'mode_of_payment',
                label: 'Mode of Payment',
                options: 'Mode of Payment',
                default: "Cash",
                reqd: 1
            },
            {
                fieldtype: 'Check',
                fieldname: 'registration_only',
                label: 'Registration Only',
                depends_on: enable_registration_only ? "" : "eval:0", // Hide if already registered
                change: function() {
                    let reg_only = dialog.get_value('registration_only');

                    // Hide/disable consultation-related fields when registration_only is checked
                    dialog.set_df_property('doctor_name', 'reqd', !reg_only);

                    dialog.set_value('doctor_name', '', reg_only);
                    dialog.set_value('token_number', '', reg_only);
                    dialog.set_value('consultation_charge', '', reg_only);
                    dialog.set_value('consultation_validity_info', '', reg_only);


                    // Toggle visibility of appropriate fields
                    dialog.fields_dict.doctor_name.$wrapper.toggle(!reg_only);
                    dialog.fields_dict.consultation_charge.$wrapper.toggle(!reg_only);
                    dialog.fields_dict.consultation_validity_info.$wrapper.toggle(!reg_only);
                    dialog.fields_dict.token_number.$wrapper.toggle(!reg_only);

                    // Update the items table to show/hide consultation fee
                    updateTable(
                        dialog,
                        parseFloat(dialog.registration_fee || 0),
                        reg_only ? 0 : parseFloat(dialog.get_value('consultation_charge') || 0),
                        frm.doc.custom_is_registered,
                        frm,
                        reg_only ? null : dialog.get_value('doctor_name')
                    );

                    // Toggle buttons visibility
                    if(reg_only) {
                        dialog.get_primary_btn().show();
                        dialog.get_secondary_btn().hide();
                    } else {
                        // If doctor is selected, manage button visibility based on consultation validity
                        let doctor = dialog.get_value('doctor_name');
                        if(doctor) {
                            checkConsultationValidity(frm, doctor, dialog);
                        }
                    }
                }
            },
            {
                fieldtype: 'Section Break'
            },
            {
                fieldtype: 'HTML',
                fieldname: 'items_table'
            }
        ],
        primary_action_label: "Generate Bill",
        primary_action: function(values) {
            frappe.confirm(
                __('Are you sure you want to generate this bill?'),
                function() {
                    // If confirmed
                    let generate_btn = dialog.get_primary_btn();
                    generate_btn.prop('disabled', true); // Disable button
                    generate_btn.html(`<i class="fa fa-spinner fa-spin"></i> Generating...`); // Show loading indicator

                    let reg_fee = parseFloat(dialog.registration_fee || 0);
                    let consult_fee = parseFloat(values.consultation_charge || 0);
                    let items = [];

                    if (!is_registered && reg_fee > 0) {
                        items.push({
                            item_code: "Registration Fee",
                            qty: 1,
                            rate: reg_fee
                        });
                    }

                    if (consult_fee > 0 && !dialog.consultation_valid) {
                        items.push({
                            item_code: "Consultation Fee",
                            qty: 1,
                            rate: consult_fee
                        });
                    }

                    if (items.length === 0) {
                        frappe.msgprint(__('Please select at least one service before generating an invoice'), 'Warning');
                        generate_btn.prop('disabled', false).html('Generate Bill'); // Reset button
                        return;
                    }

                    console.log("token", values.token_number);

                    // add token to token history
                    if(values.token_number){
                        frappe.call({
                            method: 'frappe.client.get',
                            args: {
                                doctype: 'Healthcare Practitioner',
                                name: values.doctor_name
                            },
                            callback: function(r) {
                                if (r.message) {
                                    let doctor_doc = r.message;
                                    let today = frappe.datetime.get_today();
                                    let token_series = cached_token.split('-')[0];
                                    let last_token = parseInt(cached_token.split('-')[1]);

                                    doctor_doc.custom_token_history = doctor_doc.custom_token_history || [];

                                    // Check if today's entry exists
                                    let today_entry = doctor_doc.custom_token_history.find(entry => entry.date === today);

                                    if (today_entry) {
                                        // Update the existing token
                                        today_entry.last_token = last_token;
                                    } else {
                                        // Add new token entry
                                        doctor_doc.custom_token_history.push({
                                            token_series: token_series,
                                            last_token: last_token,
                                            date: today
                                        });
                                    }

                                    frappe.call({
                                        method: 'frappe.client.save',
                                        args: {
                                            doc: doctor_doc
                                        },
                                        callback: function() {
