                                        indicator: 'green'
                                    });

                                    dialog.hide();
                                    // Refresh the form to show updated registration status
                                    frm.reload_doc();
                                    frappe.set_route('print', 'Sales Invoice', r.message.sales_invoice);
                                } else if (r.exc) {
