                    }
                });

                const encounters = result.message || [];
                if (!encounters.length) {
                    frappe.msgprint('No Patient Encounters found for this patient.');
                    return;
                }

                const enc_html = `
                    <style>
                        .encounter-table { border-collapse:separate; border-spacing:0; width:100%;
                            border-radius:8px; overflow:hidden; box-shadow:0 2px 4px rgba(0,0,0,.1); }
                        .encounter-table thead { background:#4172b4; color:#fff; }
                        .encounter-table th { padding:12px 15px; font-weight:600; text-align:left; font-size:13px; }
                        .encounter-table td { padding:10px 15px; border-bottom:1px solid #e0e0e0; vertical-align:middle; }
                        .encounter-table tbody tr:last-child td { border-bottom:none; }
                        .encounter-table tbody tr:nth-child(even) { background:#f7f9fc; }
                        .encounter-table tbody tr:hover { background:#f0f4f9; }
                        .enc-checkbox { width:18px; height:18px; cursor:pointer; accent-color:#4172b4; }
                        .enc-date  { color:#555; font-weight:500; }
                        .enc-token { font-weight:600; color:#4172b4; }
                        .table-container { padding:15px; max-height:400px; overflow-y:auto; }
                    </style>
                    <div class="table-container">
                        <table class="encounter-table">
                            <thead>
                                <tr><th style="width:60px">Select</th><th>Encounter</th><th>Date</th><th>Token</th></tr>
                            </thead>
                            <tbody>
                                ${encounters.map(enc => `
                                    <tr>
                                        <td style="text-align:center">
                                            <input type="checkbox" class="enc-radio enc-checkbox" value="${enc.name}"/>
                                        </td>
                                        <td>${enc.title || 'Untitled Encounter'}</td>
                                        <td class="enc-date">${frappe.datetime.str_to_user(enc.encounter_date)}</td>
                                        <td class="enc-token">${enc.custom_encounter_token || '-'}</td>
                                    </tr>`).join('')}
                            </tbody>
                        </table>
                    </div>`;

                const d = new frappe.ui.Dialog({
                    title: 'Select Patient Encounter',
                    fields: [{ fieldname: 'encounter_table', fieldtype: 'HTML', options: enc_html }],
                    primary_action_label: 'Get Prescription',
                    primary_action: function () {
                        const selected = d.$wrapper.find('input.enc-radio:checked').val();
                        if (!selected) {
                            frappe.msgprint('Please select an encounter first.');
                            return;
                        }

                        frappe.call({
                            method: 'frappe.client.get',
                            args: { doctype: 'Patient Encounter', name: selected },
                            callback: function (data) {
                                if (!data.message) {
                                    frappe.msgprint('Could not fetch encounter details.');
                                    return;
                                }
                                const encounter = data.message;
                                if (!encounter.custom_medicine_prescription || !encounter.custom_medicine_prescription.length) {
                                    frappe.msgprint('No medicine prescriptions found in this encounter.');
                                    return;
                                }

                                frm.doc.medicines = frm.doc.medicines || [];
                                encounter.custom_medicine_prescription.forEach(med => {
                                    const row       = frappe.model.add_child(frm.doc, 'Pharmaceuticals', 'medicines');
                                    row.item_code   = med.item_code;
                                    row.item_name   = med.item_name;
                                    row.hsn         = med.hsn;
                                    row.batch       = med.batch;
                                    row.expiry_date = med.expiry_date;
                                    row.mrp         = med.mrp;
                                    row.qty         = med.qty;
                                });

                                frm.refresh_field('medicines');
                                frappe.show_alert({
                                    message: __('Added {0} medicine(s) from prescription', [encounter.custom_medicine_prescription.length]),
                                    indicator: 'green'
                                }, 5);

                                if (frm.fields_dict.encounter) {
                                    frm.set_value('encounter', selected);
                                }
                            }
                        });
                        d.hide();
                    }
                });

                d.show();
                d.$wrapper.find('.modal-dialog').css('max-width', '700px');

                // Checkboxes behave like radio buttons
                d.$wrapper.on('change', '.enc-radio', function () {
                    if ($(this).is(':checked')) {
                        d.$wrapper.find('.enc-radio').not(this).prop('checked', false);
                    }
                });

            } catch (err) {
                console.error(err);
                frappe.msgprint('Error fetching Patient Encounters.');
            }
        });
    },

    /* ---------- patient_name: auto-fill doctor ---------- */
    patient_name: function (frm) {
        if (!frm.doc.patient_name) return;
        frappe.call({
            method: 'health_sil.services.appointment_api.check_last_encounter',
            args: { patient: frm.doc.patient_name },
            callback: function (r) {
                if (r.message && r.message.has_encounter) {
                    frm.set_value('healthcare_practitioner', r.message.doctor);
                }
            }
        });
    },

    /* ---------- healthcare_practitioner: auto-fill department ---------- */
    healthcare_practitioner: function (frm) {
        if (!frm.doc.healthcare_practitioner) return;
        frappe.db.get_value('Healthcare Practitioner', frm.doc.healthcare_practitioner, 'department')
            .then(r => {
                if (r.message && r.message.department) {
                    frm.set_value('department', r.message.department);
                }
            })
            .catch(err => console.error('Error fetching department:', err));
    },

    /* ---------- on_submit: create sales invoice ---------- */
    on_submit: function (frm) {
        const items = (frm.doc.medicines || []).map(row => ({
            item_code:             row.item_code,
            item_name:             row.item_name,
            qty:                   row.qty,
            rate:                  row.new_mrp,
            amount:                row.final_total,
            amount_before_discount: row.amount,
            batch_no:              row.batch
        }));

        frappe.call({
            method: 'health_sil.services.generate_invoice_api.create_sales_invoice',
            args: {
                patient:             frm.doc.name,
                patient_name:        frm.doc.patient_name,
                doctor:              frm.doc.healthcare_practitioner,
                mode_of_payment:     frm.doc.custom_mode_of_payment,
                items:               items
            },
            callback: function (r) {
                if (r.message) {
                    frappe.msgprint({
                        title:     __('Invoice & Payment Created'),
                        message:   __('Sales Invoice {0} and Payment Entry generated successfully.', [r.message.name]),
                        indicator: 'green'
                    });
                    frappe.set_route('print', 'Pharmacy Billing', frm.doc.name);
                }
            }
        });
    },

    /* ---------- before_print: choose format by row count ---------- */
    before_print: function (frm) {
        frm.meta.default_print_format =
            (frm.doc.medicines || []).length > 10 ? 'Long Invoice Format' : 'Pharmacy Inv';
    },

    /* ---------- validate ---------- */
    validate: function (frm) {
        const required_main = ['patient_name', 'healthcare_practitioner', 'total_amount'];
        const required_row  = ['item_code', 'qty', 'mrp', 'amount', 'gst_'];

        const missing = required_main.filter(f => !frm.doc[f])
            .map(f => __(frappe.meta.get_label(frm.doctype, f, frm.doc.name)));

        if (frm.doc.medicines && frm.doc.medicines.length > 0) {
            for (const row of frm.doc.medicines) {
                for (const field of required_row) {
                    const invalid = field === 'qty'
                        ? (!row[field] || row[field] <= 0)
                        : !row[field];
                    if (invalid) {
                        frappe.msgprint(
                            field === 'qty'
                                ? __('Qty must be greater than zero in all rows of the medicines table.')
                                : __('Please fill all required fields in the medicines table before saving.')
                        );
                        frappe.validated = false;
                        return;
                    }
                }
            }
        }

        if (missing.length > 0) {
            frappe.msgprint({
                title:     __('Missing Fields'),
                message:   __('Please fill in the following fields before saving:') + '<br><b>' + missing.join(', ') + '</b>',
                indicator: 'red'
            });
            frappe.validated = false;
        }
    },

    /* ---------- discount triggers ---------- */
    custom_discount_mode:          (frm) => calculate_totals(frm),
    custom_amount_of_discount:     (frm) => { if (frm.doc.custom_discount_mode === 'Cash')       calculate_totals(frm); },
    custom_percentage_of_discount: (frm) => { if (frm.doc.custom_discount_mode === 'Percentage') calculate_totals(frm); }
});


/* ============================================================
   2.  PHARMACEUTICALS — child-table events
   ============================================================ */
frappe.ui.form.on('Pharmaceuticals', {

    /* ---------- medicines_add: SINGLE merged handler ---------- */
    medicines_add: function (frm, cdt, cdn) {
        const row      = locals[cdt][cdn];
        const medicines = frm.doc.medicines || [];

        // Guard 1 — duplicate item+batch
        const is_duplicate = medicines.some(med =>
            med.item_code === row.item_code &&
            med.batch && row.batch &&
            med.batch === row.batch &&
            med.name !== row.name
        );
        if (is_duplicate) {
            frappe.msgprint(__('This medicine is already added. Please update the quantity instead.'));
            frappe.model.delete_doc(cdt, cdn);
            frm.refresh_field('medicines');
            return;
        }

        // Guard 2 — previous row must be complete
        if (medicines.length > 1) {
            const prev_row = medicines[medicines.length - 2];
            if (prev_row) {
                const required = ['item_code', 'qty', 'mrp', 'amount'];
                for (const field of required) {
                    const invalid = field === 'qty'
                        ? (!prev_row[field] || prev_row[field] <= 0)
                        : !prev_row[field];
                    if (invalid) {
                        frappe.msgprint(__('Please complete the previous row before adding a new one.'));
                        frappe.model.delete_doc(cdt, cdn);
                        frm.refresh_field('medicines');
                        return;
                    }
                }
            }
        }

        calculate_totals(frm);
    },

    /* ---------- medicines_remove ---------- */
    medicines_remove: function (frm) {
        calculate_totals(frm);
    },

    /* ---------- item_code ---------- */
    item_code: function (frm, cdt, cdn) {
        const row       = locals[cdt][cdn];
        const medicines = frm.doc.medicines || [];

        // Block re-entry — modal.js fires a change event when dialog opens
        // which re-triggers item_code for the same row
        if (_fetching_rows.has(cdn)) return;

        const is_duplicate = medicines.some(med =>
            med.item_code === row.item_code &&
            med.batch && row.batch &&
            med.batch === row.batch &&
            med.name !== row.name
        );
        if (is_duplicate) {
            frappe.msgprint(__('This medicine is already added. Update the quantity instead.'));
            frappe.model.set_value(cdt, cdn, 'item_code', '');
            frappe.model.set_value(cdt, cdn, 'item_name', '');
            frm.refresh_field('medicines');
            return;
        }

        if (row.item_code) {
            _fetching_rows.add(cdn);
            fetch_item_details(frm, cdt, cdn, 'item_code', row.item_code, () => {
                _fetching_rows.delete(cdn);
            });
        }
    },

    /* ---------- item_name ---------- */
    // IMPORTANT: Never call fetch_item_details here directly.
    // Frappe fires BOTH item_code and item_name when user picks from dropdown.
    // item_code trigger alone handles all fetching.
    // This handler only resolves item_code when user manually types a name
    // and item_code is still empty — setting item_code fires item_code trigger automatically.
    item_name: function (frm, cdt, cdn) {
        const row = locals[cdt][cdn];
        if (!row.item_name) return;

        // item_code already set means item_code trigger already handled it — skip
        if (row.item_code) return;

        frappe.db.get_value('Item', { item_name: row.item_name }, 'name')
            .then(res => {
                if (res.message && res.message.name) {
                    // This will fire the item_code trigger which handles fetch + dialog
                    frappe.model.set_value(cdt, cdn, 'item_code', res.message.name);
                } else {
                    frappe.msgprint(__('No matching item found for the selected item name.'));
                }
            })
            .catch(err => console.error('Error fetching item by name:', err));
    },

    /* ---------- qty ---------- */
    qty: function (frm, cdt, cdn) {
        const row = locals[cdt][cdn];
        if (!row.qty || row.qty <= 0) return;

        if (row.batch) {
            frappe.call({
                method: 'health_sil.services.batch_selection_api.validate_batch_qty',
                args: { batch_no: row.batch, qty: row.qty },
                callback: function (r) {
                    if (r.message && !r.message.ok) {
                        frappe.msgprint({ title: __('Insufficient Stock'), message: __(r.message.message), indicator: 'red' });
                        frappe.model.set_value(cdt, cdn, 'qty', 0);
                        return;
                    }
                    apply_row_calculations(frm, cdt, cdn);
                }
            });
        } else {
            apply_row_calculations(frm, cdt, cdn);
        }
    },

    /* ---------- discount_ ---------- */
    discount_: function (frm, cdt, cdn) {
        const row            = locals[cdt][cdn];
        const base_amount    = row.custom_first_total_amount || 0;
        const discount_amount = row.discount_ || 0;
        const total          = base_amount - discount_amount;

        frappe.model.set_value(cdt, cdn, 'discounted_amount', discount_amount);
        frappe.model.set_value(cdt, cdn, 'total_amount',      total);
        frappe.model.set_value(cdt, cdn, 'amount',            total);
        frm.refresh_field('medicines');
        calculate_totals(frm);
    }
});


/* ============================================================
   3.  HELPER — apply_row_calculations
   ============================================================ */
function apply_row_calculations(frm, cdt, cdn, skip_refresh) {
    const row               = locals[cdt][cdn];
    const tablets_per_strip = row.tablets_per_strip || 1;

    // Strips and NOS breakdown
    if (tablets_per_strip > 0) {
        frappe.model.set_value(cdt, cdn, 'strips', Math.floor(row.qty / tablets_per_strip) || 0);
        frappe.model.set_value(cdt, cdn, 'nos',    row.qty % tablets_per_strip || 0);
    } else {
        frappe.model.set_value(cdt, cdn, 'strips', 0);
        frappe.model.set_value(cdt, cdn, 'nos',    row.qty);
    }

    // Use MRP per tablet (row.mrp) for amount — NOT strip price (custom_actual_mrp)
    const mrp_per_tablet        = row.mrp || 0;
    const qty                   = row.qty || 0;
    const discount              = row.discount_ || 0;
    const total_before_discount = mrp_per_tablet * qty;
    const total_after_discount  = total_before_discount - discount;

    frappe.model.set_value(cdt, cdn, 'amount',                    total_after_discount);
    frappe.model.set_value(cdt, cdn, 'custom_first_total_amount', total_after_discount);
    frappe.model.set_value(cdt, cdn, 'discounted_amount',         discount);

    // GST back-calculation (MRP is GST-inclusive)
    const gst_rate        = row.gst_ || 0;
    const amount_before_tax = flt(total_after_discount / (1 + gst_rate / 100), 2);
    const tax_amount        = flt(total_after_discount - amount_before_tax, 2);
    const cgst_amount       = flt(tax_amount / 2, 2);
    const sgst_amount       = flt(tax_amount / 2, 2);

    frappe.model.set_value(cdt, cdn, 'amount_before_tax', amount_before_tax);
    frappe.model.set_value(cdt, cdn, 'tax_amount',        tax_amount);
    frappe.model.set_value(cdt, cdn, 'cgst_amount',       cgst_amount);
    frappe.model.set_value(cdt, cdn, 'sgst_amount',       sgst_amount);

    if (!skip_refresh) {
        frm.refresh_field('medicines');
        calculate_totals(frm);
    }
}


/* ============================================================
   4.  HELPER — show_batch_selection_dialog
   ============================================================ */
function show_batch_selection_dialog(frm, cdt, cdn, item_code, mrp) {
    mrp = mrp || locals[cdt][cdn].custom_actual_mrp || locals[cdt][cdn].mrp || 0;

    frappe.call({
        method: 'health_sil.services.batch_selection_api.get_batches_for_item',
        args: { item_code: item_code },
        callback: function (r) {
            const batches = r.message || [];
            if (batches.length === 0) {
                _fetching_rows.delete(cdn);
                frappe.msgprint({ title: __('No Stock'), message: __('No stock available for this item.'), indicator: 'red' });
                return;
            }

            // Single batch — auto-select, no dialog needed
            if (batches.length === 1) {
                const b = batches[0];
                frappe.model.set_value(cdt, cdn, 'batch',             b.batch_no);
                frappe.model.set_value(cdt, cdn, 'expiry_date',       b.expiry_date || '');
                frappe.model.set_value(cdt, cdn, 'mrp',               b.mrp_per_tablet || 0);
                frappe.model.set_value(cdt, cdn, 'custom_actual_mrp', b.mrp_per_strip || 0);
                frappe.model.set_value(cdt, cdn, 'strips',            b.strips || 1);
                frappe.model.set_value(cdt, cdn, 'tablets_per_strip', b.strips || 1);
                apply_row_calculations(frm, cdt, cdn, false);
                _fetching_rows.delete(cdn);
                return;
            }

            // Multiple batches — show selection dialog
            const rows_html = batches.map(b => {
                const avail_class   = b.qty_available <= 10 ? 'avail-low' : 'avail-ok';
                const expiry_display = b.expiry_date ? frappe.datetime.str_to_user(b.expiry_date) : __('N/A');
                return `
                    <tr>
                        <td><input type="checkbox" class="row-check" data-batch="${b.batch_no}" /></td>
                        <td><b>${b.batch_no}</b></td>
                        <td>${expiry_display}</td>
                        <td class="${avail_class}">${b.qty_available}</td>
                        <td>₹${(b.mrp_per_tablet || 0).toFixed(2)}</td>
                        <td>₹${(b.mrp_per_strip  || 0).toFixed(2)}</td>
                        <td>
                            <input type="number" min="0" step="1" class="batch-qty-input"
                                data-batch="${b.batch_no}" data-expiry="${b.expiry_date || ''}"
                                data-avail="${b.qty_available}" data-mrpt="${b.mrp_per_tablet || 0}"
                                data-mrps="${b.mrp_per_strip  || 0}" data-strips="${b.strips || 1}"
                                placeholder="0" />
                        </td>
                    </tr>`;
            }).join('');

            const table_html = `
                <style>
                    .batch-sel-table { width:100%; border-collapse:collapse; font-size:13px; }
                    .batch-sel-table th,.batch-sel-table td { padding:8px 10px; border-bottom:1px solid #eee; text-align:left; }
                    .batch-sel-table th { background:#f5f5f5; font-weight:600; }
                    .batch-qty-input { width:80px; padding:4px 6px; border:1px solid #ccc;
                        border-radius:4px; font-size:13px; text-align:right; }
                    .batch-qty-input:focus { border-color:#5e64ff; outline:none; }
                    .avail-low { color:#d9534f; font-weight:bold; }
                    .avail-ok  { color:#5cb85c; }
                </style>
                <table class="batch-sel-table">
                    <thead>
                        <tr>
                            <th style="width:40px"><input type="checkbox" id="select-all-batches" /></th>
                            <th>Batch No</th><th>Expiry Date</th><th>Available Qty</th>
                            <th>MRP/Tablet (₹)</th><th>MRP/Strip (₹)</th><th>Bill Qty</th>
                        </tr>
                    </thead>
                    <tbody>${rows_html}</tbody>
                </table>`;

            const d = new frappe.ui.Dialog({
                title: __('Select Batch & Enter Qty for {0}', [item_code]),
                fields: [{ fieldtype: 'HTML', fieldname: 'batch_table', options: table_html }],
                size: 'large',
                primary_action_label: __('Confirm Selection'),
                primary_action: function () {
                    const selected_entries = [];
                    let has_error = false;

                    d.$wrapper.find('.batch-qty-input').each(function () {
                        const batch_id  = $(this).data('batch');
                        const checkbox  = d.$wrapper.find(`.row-check[data-batch="${batch_id}"]`);
                        const qty       = parseFloat($(this).val()) || 0;
                        const is_checked = checkbox.prop('checked');

                        if (!is_checked && qty <= 0) return; // skip untouched rows

                        if (qty <= 0) {
                            frappe.msgprint(__('Please enter a valid Bill Qty for selected batch {0}', [batch_id]));
                            has_error = true;
                            return false;
                        }

                        const avail = parseFloat($(this).data('avail')) || 0;
                        if (qty > avail) {
                            frappe.msgprint(__('Qty {0} exceeds available stock of {1} for batch {2}', [qty, avail, batch_id]));
                            has_error = true;
                            return false;
                        }

                        selected_entries.push({
                            batch_no:      batch_id,
                            expiry_date:   $(this).data('expiry'),
                            mrp_per_tablet: parseFloat($(this).data('mrpt')) || 0,
                            mrp_per_strip:  parseFloat($(this).data('mrps')) || 0,
                            strips:         parseFloat($(this).data('strips')) || 1,
                            qty:            qty
                        });
                    });

                    if (has_error) return;
                    if (selected_entries.length === 0) {
                        frappe.msgprint(__('Please select at least one batch or enter a Bill Qty.'));
                        return;
                    }

                    d.hide();

                    const orig  = locals[cdt][cdn];
                    const first = selected_entries[0];

                    frappe.model.set_value(cdt, cdn, 'batch',             first.batch_no);
                    frappe.model.set_value(cdt, cdn, 'expiry_date',       first.expiry_date);
                    frappe.model.set_value(cdt, cdn, 'mrp',               first.mrp_per_tablet);
                    frappe.model.set_value(cdt, cdn, 'custom_actual_mrp', first.mrp_per_strip);
                    frappe.model.set_value(cdt, cdn, 'strips',            first.strips);
                    frappe.model.set_value(cdt, cdn, 'tablets_per_strip', first.strips);
                    frappe.model.set_value(cdt, cdn, 'qty',               first.qty);

                    setTimeout(() => apply_row_calculations(frm, cdt, cdn, true), 100);

                    // Additional batches → new child rows
                    for (let i = 1; i < selected_entries.length; i++) {
                        const e       = selected_entries[i];
                        const new_row = frappe.model.add_child(frm.doc, 'Pharmaceuticals', 'medicines');
                        new_row.item_code             = orig.item_code;
                        new_row.item_name             = orig.item_name;
                        new_row.hsn                   = orig.hsn;
                        new_row.mrp                   = e.mrp_per_tablet;
                        new_row.custom_actual_mrp     = e.mrp_per_strip;
                        new_row.custom_first_total_amount = 0;
                        new_row.strips                = e.strips;
                        new_row.tablets_per_strip     = e.strips;
                        new_row.gst_                  = orig.gst_;
                        new_row.batch                 = e.batch_no;
                        new_row.expiry_date           = e.expiry_date || '';
                        new_row.qty                   = e.qty;
                        apply_row_calculations(frm, new_row.doctype, new_row.name, true);
                    }

                    frm.refresh_field('medicines');
                    calculate_totals(frm);
                }
            });

            // Wire up select-all and auto-check on qty input
            setTimeout(() => {
                d.$wrapper.find('#select-all-batches').on('change', function () {
                    d.$wrapper.find('.row-check').prop('checked', $(this).prop('checked'));
                });
                d.$wrapper.find('.batch-qty-input').on('keyup input', function () {
                    const val      = parseFloat($(this).val()) || 0;
                    const batch_id = $(this).data('batch');
                    d.$wrapper.find(`.row-check[data-batch="${batch_id}"]`).prop('checked', val > 0);
                });
            }, 100);

            d.show();
            // Release the row lock when dialog is closed (hides or confirmed)
            // This is safer than a timeout — lock stays until user is done with dialog
            d.$wrapper.on('hidden.bs.modal', function() {
                _fetching_rows.delete(cdn);
            });
        }
    });
}


/* ============================================================
   5.  HELPER — fetch_item_details
   ============================================================ */
function fetch_item_details(frm, cdt, cdn, field, value, done) {
    if (!value) return;

    frappe.call({
        method: 'frappe.client.get',
        args: { doctype: 'Item', name: value },
        callback: function (r) {
            if (!r.message) {
                frappe.msgprint(__('Item details not found!'));
                if (done) done();
                return;
            }
            const item = r.message;

            // NOTE: Do NOT set item_code here — it's already set and
            // calling set_value on it re-triggers the item_code event → double dialog
            frappe.model.set_value(cdt, cdn, 'item_name',         item.item_name || '');

            // MRP per tablet (GST inclusive) — used for billing calculation
            const mrp_per_tablet = item.custom_mrp || 0;
            // MRP per strip (GST inclusive)
            const mrp_per_strip  = item.custom_mrp_per_purchase_uom || 0;
            // Derive tablets per strip from the two MRP values
            const tablets_per_strip = (mrp_per_strip && mrp_per_tablet)
                ? Math.round(mrp_per_strip / mrp_per_tablet)
                : 1;
            frappe.model.set_value(cdt, cdn, 'hsn',               item.gst_hsn_code || '');
            frappe.model.set_value(cdt, cdn, 'mrp',               mrp_per_tablet);
            frappe.model.set_value(cdt, cdn, 'custom_actual_mrp', mrp_per_strip);
            frappe.model.set_value(cdt, cdn, 'tablets_per_strip', tablets_per_strip);

            const taxes = item.taxes || [];
            if (taxes.length > 0 && taxes[0].item_tax_template) {
                frappe.call({
                    method: 'frappe.client.get_value',
                    args: {
                        doctype:   'Item Tax Template',
                        fieldname: 'gst_rate',
                        filters:   { name: taxes[0].item_tax_template }
                    },
                    callback: function (res2) {
                        const gst = res2.message && res2.message.gst_rate !== undefined
                            ? res2.message.gst_rate : 0;
                        frappe.model.set_value(cdt, cdn, 'gst_', gst);
                        show_batch_selection_dialog(frm, cdt, cdn, value, mrp_per_tablet);
                    }
                });
            } else {
                frappe.model.set_value(cdt, cdn, 'gst_', 0);
                show_batch_selection_dialog(frm, cdt, cdn, value, mrp_per_tablet);
            }
        }
    });
}


/* ============================================================
   6.  HELPER — calculate_totals
   ============================================================ */
function calculate_totals(frm) {
    let total_qty         = 0;
    let total_before_tax  = 0;
    let total_cgst        = 0;
    let total_sgst        = 0;
    let total_tax         = 0;
    let grand_total       = 0;
    let saved_amount      = 0;
    let total_items       = 0;

    (frm.doc.medicines || []).forEach(row => {
        total_qty        += row.qty               || 0;
        total_before_tax += row.amount_before_tax || 0;
        total_cgst       += row.cgst_amount       || 0;
        total_sgst       += row.sgst_amount       || 0;
        total_tax        += row.tax_amount        || 0;
        grand_total      += row.amount            || 0;
        saved_amount     += row.discounted_amount || 0;
        total_items++;
    });

    frm.set_value('total_quantity',            total_qty);
    frm.set_value('custom_sub_total_before_tax', total_before_tax);
    frm.set_value('custom_total_cgst',         total_cgst);
    frm.set_value('custom_total_sgst',         total_sgst);
    frm.set_value('custom_total_tax_amount',   total_tax);
    frm.set_value('total_amount',              grand_total);
    frm.set_value('total_items',               total_items);
    frm.set_value('saved_amount',              saved_amount);

    // Apply form-level discount
    const mode  = frm.doc.custom_discount_mode;
    let discount = 0;
    if (mode === 'Cash' && frm.doc.custom_amount_of_discount) {
        discount = frm.doc.custom_amount_of_discount;
    } else if (mode === 'Percentage' && frm.doc.custom_percentage_of_discount) {
        discount = (grand_total * frm.doc.custom_percentage_of_discount) / 100;
    }

    const final_total = grand_total - discount;
    frm.set_value('total_amount',  final_total);
    frm.set_value('saved_amount',  saved_amount + discount);

    const rounded = Math.round(final_total);
    frm.set_value('rounded_total_amount', rounded);

    frappe.call({
        method: 'health_sil.services.money_in_words_api.money_in_words_api',
        args: { amount: rounded },
        callback: function (r) {
            if (r.message) frm.set_value('amount_in_words', r.message);
        }
    });

    frm.refresh_fields([
        'total_quantity', 'total_amount', 'custom_total_tax_amount',
        'custom_total_cgst', 'custom_total_sgst', 'custom_sub_total_before_tax',
        'total_items', 'saved_amount', 'rounded_total_amount'
    ]);
}

