        const missing_fields = required_fields.filter(field => !frm.doc[field]);

        if (frm.doc.nursing_items?.length > 0) {
            const incomplete_row = frm.doc.nursing_items.find(row =>
                !row.item_code || !row.rate || !row.amount_before_discount
