            if (incomplete_row) {
                frappe.msgprint(__("Please fill all required fields in the Nursing Items table before saving."));
                frappe.validated = false;
                return;
            }
        }

        if (missing_fields.length > 0) {
            frappe.msgprint({
                title: __("Missing Fields"),
                message: __("Please fill in the following fields before saving:") + "<br><b>" +
                    missing_fields.map(f => __(frappe.meta.get_label(frm.doctype, f, frm.doc.name))).join(", ") + "</b>",
                indicator: "red"
            });
            frappe.validated = false;
        }
    },

    custom_discount_mode(frm) {
        calculate_totals(frm);
    },
    custom_amount_of_discount(frm) {
        if (frm.doc.custom_discount_mode === "Cash") {
            calculate_totals(frm);
        }
    },
    custom_percentage_of_discount(frm) {
        if (frm.doc.custom_discount_mode === "Percentage") {
            calculate_totals(frm);
        }
    }
});

