// Utility - Total Calculation
function calculate_totals(frm) {
    let total_qty = 0, total_before_discount = 0, total_items = 0;

    (frm.doc.nursing_items || []).forEach(row => {
        total_qty += row.qty || 0;
        total_before_discount += row.amount_before_discount || 0;
    });

    total_items = frm.doc.nursing_items?.length || 0;

    let discount_mode = frm.doc.custom_discount_mode;
    let discount_value = 0;

    if (discount_mode === "Cash" && frm.doc.custom_amount_of_discount) {
        discount_value = frm.doc.custom_amount_of_discount;
    } else if (discount_mode === "Percentage" && frm.doc.custom_percentage_of_discount) {
        discount_value = (total_before_discount * frm.doc.custom_percentage_of_discount) / 100;
    }

    const final_total = total_before_discount - discount_value;
    const rounded_total = Math.round(final_total);

    frm.set_value({
        total_quantity: total_qty,
        total_amount: final_total,
        total_items,
        saved_amount: discount_value,
        rounded_total_amount: rounded_total
    });

    frappe.call({
        method: "health_sil.services.money_in_words_api.money_in_words_api",
        args: { amount: rounded_total },
        callback(r) {
            if (r.message) {
                frm.set_value("amount_in_words", r.message);
            }
        }
    });

    frm.refresh_fields([
        "total_quantity", "total_amount", "total_items",
        "saved_amount", "rounded_total_amount"
    ]);
}

