        // Validate lab items table
        if (frm.doc.lab_items?.length > 0) {
            const incomplete_row = frm.doc.lab_items.find(row => 
                !row.item_code || !row.rate || !row.amount_before_discount
            );

            if (incomplete_row) {
                frappe.msgprint(__("Please fill all required fields in the Lab Items table before saving."));
                frappe.validated = false;
                return;
            }
        }

        // Validate required fields
        if (missing_fields.length > 0) {
            frappe.msgprint({
                title: __("Missing Fields"),
                message: __("Please fill in the following fields before saving:") + 
                        "<br><b>" + 
                        missing_fields.map(f => __(frappe.meta.get_label(frm.doctype, f, frm.doc.name))).join(", ") + 
                        "</b>",
                indicator: "red"
            });
            frappe.validated = false;
        }
    },

    custom_discount_mode: function(frm) {
        calculate_totals(frm);
    },

    custom_amount_of_discount: function(frm) {
        if (frm.doc.custom_discount_mode === "Cash") {
            calculate_totals(frm);
        }
    },

    custom_percentage_of_discount: function(frm) {
        if (frm.doc.custom_discount_mode === "Percentage") {
            calculate_totals(frm);
        }
    }
});

// Lab Items - Child Table
frappe.ui.form.on('Lab Items', {
    lab_items_add: function(frm) {
        calculate_totals(frm);
    },

    lab_items_remove: function(frm) {
        calculate_totals(frm);
    },

    item_code: function(frm, cdt, cdn) {
        const row = locals[cdt][cdn];

        // Prevent duplicate item codes
        const is_duplicate = (frm.doc.lab_items || []).some(item => 
            item.item_code === row.item_code && item.name !== row.name
        );

        if (is_duplicate) {
            frappe.msgprint(__('This item is already added.'));
            frappe.model.set_value(cdt, cdn, "item_code", "");
            frappe.model.set_value(cdt, cdn, "item_name", "");
            return;
        }

        if (!row.item_code) return;

        // Fetch item details
        frappe.db.get_value("Item", { item_code: row.item_code }, ["item_name", "valuation_rate"])
            .then(r => {
                if (!r.message) {
                    frappe.msgprint(__('Item details not found!'));
                    return;
                }

                const item_name = r.message.item_name;
                const item_group = r.message.item_group;

                frappe.model.set_value(cdt, cdn, "item_name", item_name);
                frappe.model.set_value(cdt, cdn, "qty", 1);

                // Use custom price logic based on territory if patient exists and item is not medication
                if (frm.doc.patient_name && item_group !== "Medications") {
                    frappe.call({
                        method: "health_sil.services.price_list_api.get_country_specific_price",
                        args: {
                            item_code: row.item_code,
                            patient_id: frm.doc.patient_name
                        },
                        callback: function(res) {
                            const rate = res.message || 0;
                            frappe.model.set_value(cdt, cdn, "rate", rate);
                            frappe.model.set_value(cdt, cdn, "amount_before_discount", rate);
                            frappe.model.set_value(cdt, cdn, "amount", rate);
                            frm.refresh_field("lab_items");
                            calculate_totals(frm);
                        }
                    });
                } else {
                    // Fallback to valuation rate for Medications or no patient selected
                    frappe.db.get_value("Item", { item_code: row.item_code }, "valuation_rate")
                        .then(val => {
                            const rate = val.message?.valuation_rate || 0;
                            frappe.model.set_value(cdt, cdn, "rate", rate);
                            frappe.model.set_value(cdt, cdn, "amount_before_discount", rate);
                            frappe.model.set_value(cdt, cdn, "amount", rate);
                            frm.refresh_field("lab_items");
                            calculate_totals(frm);
                        });
                }
            })
            .catch(err => {
                console.error('Error fetching item info:', err);
            });
    }
});

// Utility Functions
function calculate_totals(frm) {
    let total_qty = 0;
    let total_before_discount = 0;
    let total_items = 0;

    // Calculate totals from lab items
    (frm.doc.lab_items || []).forEach(row => {
        total_qty += row.qty || 0;
        total_before_discount += row.amount_before_discount || 0;
    });

    total_items = frm.doc.lab_items?.length || 0;

    // Calculate discount
    const discount_mode = frm.doc.custom_discount_mode;
    let discount_value = 0;

    if (discount_mode === "Cash" && frm.doc.custom_amount_of_discount) {
        discount_value = frm.doc.custom_amount_of_discount;
    } else if (discount_mode === "Percentage" && frm.doc.custom_percentage_of_discount) {
        discount_value = (total_before_discount * frm.doc.custom_percentage_of_discount) / 100;
    }

    // Calculate final totals
    const final_total = total_before_discount - discount_value;
    const rounded_total = Math.round(final_total);

    // Set calculated values
    frm.set_value("total_quantity", total_qty);
    frm.set_value("total_amount", final_total);
    frm.set_value("total_items", total_items);
    frm.set_value("saved_amount", discount_value);
    frm.set_value("rounded_total_amount", rounded_total);

    // Convert amount to words
    frappe.call({
        method: "health_sil.services.money_in_words_api.money_in_words_api",
        args: { amount: rounded_total },
        callback: function(r) {
            if (r.message) {
                frm.set_value("amount_in_words", r.message);
            }
        }
    });

    // Refresh fields
    frm.refresh_fields([
        "total_quantity",
        "total_amount", 
        "total_items",
        "saved_amount",
        "rounded_total_amount"
    ]);
}

function open_result_dialog(lab_test_id) {
