                        background-color: #000;
                        color: #fff;
                        font-weight: bold;
                    }
                    .normal-range-cell {
                        white-space: pre-line;
                        font-size: 11px;
                        line-height: 1.4;
                        max-width: 200px;
                        word-wrap: break-word;
                    }
                </style>
                <table class="table lab-result-table">
                    <thead class="lab-result-header">
                        <tr>
                            <th>Test</th>
                            <th>Event</th>
                            <th>Result</th>
                            <th>UOM</th>
                            <th>Normal Range</th>
                        </tr>
                    </thead>
                    <tbody>`;

            r.message.rows.forEach(row => {
                // Format the normal range to preserve line breaks
                let normalRangeFormatted = (row.normal_range || '');
                // Replace any \n or \\n with actual line breaks, and clean up extra spaces
                // normalRangeFormatted = normalRangeFormatted
                //     .replace(/\\n/g, '<br>')
                //     .replace(/\n+/g, '<br>')
                //     .trim();

                html += `
                    <tr>
                        <td>${row.lab_test_name}</td>                        
                        <td>${row.event_name}</td>
                        <td><input type="text" class="form-control form-control-sm" style="border: 1px solid #000" data-name="${row.name}" name="result_value_${row.name}" /></td>
                        <td>${row.uom || ''}</td>
                        <td class="normal-range-cell">${normalRangeFormatted}</td>
                    </tr>`;
            });
            html += `</tbody></table>`;

            const resultDialog = new frappe.ui.Dialog({
                title: `Enter Results - ${r.message.template}`,
                fields: [{
                    fieldname: "results_table",
                    fieldtype: "HTML",
                    options: html
                }],
                primary_action_label: "Submit Results",
                primary_action() {
                    const values = {};
                    r.message.rows.forEach(row => {
                        const input = resultDialog.$wrapper.find(`[name=result_value_${row.name}]`).val();
                        values[row.name] = input;
                    });

                    // Move confirmation outside of resultDialog logic chain
                    const confirmDialog = new frappe.ui.Dialog({
                        title: "Confirm Submission",
                        fields: [
                            {
                                fieldtype: "HTML",
                                options: "<p style='color: #000;'>Are you sure you want to submit these results?</p>"
                            }
                        ],
                        primary_action_label: "Yes",
                        primary_action: () => {
                            // Submit only on confirmation
                            frappe.call({
                                method: "health_sil.services.lab_test_api.submit_lab_test_with_results",
                                args: {
                                    lab_test_id: r.message.lab_test_id,
                                    results: values
                                },
                                callback: () => {
                                    frappe.msgprint("Results saved and submitted.");
                                    confirmDialog.hide();
                                    resultDialog.hide();

                                    // Refresh only the dialog, not full form
                                    show_updated_lab_tests_dialog(cur_frm.doc.name);
                                }
                            });
                        },
                        secondary_action_label: "No",
                        secondary_action: () => {
                            confirmDialog.hide();
                            resultDialog.show(); // Return to the input dialog
                        }
                    });

                    resultDialog.hide(); // Hide temporarily
                    confirmDialog.show(); // This is critical!
                }
            });

            resultDialog.show();

            resultDialog.$wrapper.find('.modal-dialog').css({
                width: "80%",
                maxWidth: "1200px"
            });

            // Add this immediately after showing the dialog
            resultDialog.$wrapper.find('input').on('keydown', function(e) {
                if (e.key === 'Enter') e.preventDefault();
            });
        }
    });
}

