frappe.ui.form.on('Laboratory Bill', {
    patient_name: function(frm) {
        if (!frm.doc.patient_name) return;

        frm.doc.lab_items.forEach(row => {
            if (!row.item_code) return;

            frappe.call({
                method: "health_sil.services.price_list_api.get_country_specific_price",
                args: {
                    item_code: row.item_code,
                    patient_id: frm.doc.patient_name
                },
                callback: function(r) {
                    if (r.message) {
                        frappe.model.set_value(row.doctype, row.name, "rate", r.message);
                        if (row.qty) {
                            frappe.model.set_value(row.doctype, row.name, "amount", row.qty * r.message);
                            frappe.model.set_value(row.doctype, row.name, "amount_before_discount", row.qty * r.message);
                        }
                        calculate_totals(frm);
                    }
                }
            });
        });

        frappe.db.get_value('Patient', frm.doc.patient_name, 'default_price_list')
            .then(res => {
                if (res.message?.default_price_list) {
                    frm.set_value("custom_patient_price_list", res.message.default_price_list);
                }
            });

        frappe.call({
            method: 'health_sil.services.appointment_api.check_last_encounter',
            args: { patient: frm.doc.patient_name },
            callback: function(r) {
                if (r.message?.has_encounter) {
                    frm.set_value('healthcare_practitioner', r.message.doctor);
                }
            }
        });
    },

    on_submit: function(frm) {
        const items = (frm.doc.lab_items || []).map(row => ({
            item_code: row.item_code,
            item_name: row.item_name,
            qty: row.qty,
            rate: row.rate,
            amount: row.amount,
            amount_before_discount: row.amount_before_discount
        }));

        frappe.call({
            method: 'health_sil.services.generate_invoice_api.create_sales_invoice',
            args: {
                patient: frm.doc.name,
                patient_name: frm.doc.patient_name,
                doctor: frm.doc.healthcare_practitioner,
                mode_of_payment: frm.doc.custom_mode_of_payment,
                items: items,
                price_list: frm.doc.custom_patient_price_list
            },
            callback: function(r) {
                if (r.message) {
                    frappe.msgprint({
                        title: __('Invoice & Payment Created'),
                        message: __('Sales Invoice {0} and Payment Entry generated successfully.', [r.message.name]),
                        indicator: 'green'
                    });
                    frappe.set_route('print', 'Laboratory Bill', frm.doc.name);
                }
            }
        });
    },

    refresh: function(frm) {
        if (!window.labTestRealtimeBound) {
            frappe.realtime.on('lab_test_created', function(data) {
                if (data?.bill_name === frm.doc.name) {
                    frappe.show_alert({
                        message: `Lab Test result submitted for <b>${data.item_code}</b>. <a style="color:#007bff; cursor:pointer;" onclick="location.reload()">Click to refresh</a>.`,
                        indicator: 'green'
                    }, 15);
                }
            });
            window.labTestRealtimeBound = true;
        }

        if (frm.doc.docstatus === 1) {
            frm.add_custom_button("Enter Results", () => {
                show_lab_tests_dialog(frm);
            });
        }

        if (frm.doc.docstatus === 0) {
            $('button[data-original-title="Print"]').hide();
        }

        frm.fields_dict.lab_items.grid.get_field("item_code").get_query = () => ({ filters: { "item_group": "Laboratory" } });
        frm.fields_dict.lab_items.grid.get_field("item_name").get_query = () => ({ filters: { "item_group": "Laboratory" } });
    },

    validate: function(frm) {
        const required_fields = ["patient_name", "healthcare_practitioner", "total_amount"];
        const missing = required_fields.filter(field => !frm.doc[field]);

        const incomplete_row = frm.doc.lab_items?.find(row =>
            !row.item_code || !row.rate || !row.amount_before_discount
        );

        if (incomplete_row) {
            frappe.msgprint(__("Please complete all required Lab Item fields."));
            frappe.validated = false;
            return;
        }

        if (missing.length > 0) {
            frappe.msgprint({
                title: __("Missing Fields"),
                message: __("Please complete:") + "<br><b>" +
                    missing.map(f => __(frappe.meta.get_label(frm.doctype, f, frm.doc.name))).join(", ") + "</b>",
                indicator: "red"
            });
            frappe.validated = false;
        }
    },

    custom_discount_mode: calculate_totals,
    custom_amount_of_discount: function(frm) {
        if (frm.doc.custom_discount_mode === "Cash") calculate_totals(frm);
    },
    custom_percentage_of_discount: function(frm) {
        if (frm.doc.custom_discount_mode === "Percentage") calculate_totals(frm);
    }
});

frappe.ui.form.on('Lab Items', {
    lab_items_add: calculate_totals,
    lab_items_remove: calculate_totals,

    item_code: function(frm, cdt, cdn) {
        const row = locals[cdt][cdn];

        const is_duplicate = frm.doc.lab_items?.some(item => item.item_code === row.item_code && item.name !== row.name);
        if (is_duplicate) {
            frappe.msgprint(__('This item is already added.'));
            frappe.model.set_value(cdt, cdn, "item_code", "");
            frappe.model.set_value(cdt, cdn, "item_name", "");
            return;
        }

        if (!row.item_code) return;

        frappe.db.get_value("Item", { item_code: row.item_code }, ["item_name", "valuation_rate", "item_group"])
            .then(r => {
                if (!r.message) return;
                frappe.model.set_value(cdt, cdn, "item_name", r.message.item_name);
                frappe.model.set_value(cdt, cdn, "qty", 1);

                const group = r.message.item_group;
                if (frm.doc.patient_name && group !== "Medications") {
                    frappe.call({
                        method: "health_sil.services.price_list_api.get_country_specific_price",
                        args: { item_code: row.item_code, patient_id: frm.doc.patient_name },
                        callback: function(res) {
                            const rate = res.message || 0;
                            ["rate", "amount", "amount_before_discount"].forEach(f => frappe.model.set_value(cdt, cdn, f, rate));
                            frm.refresh_field("lab_items");
                            calculate_totals(frm);
                        }
                    });
                } else {
                    const rate = r.message.valuation_rate || 0;
                    ["rate", "amount", "amount_before_discount"].forEach(f => frappe.model.set_value(cdt, cdn, f, rate));
                    frm.refresh_field("lab_items");
                    calculate_totals(frm);
                }
            });
    }
});

function calculate_totals(frm) {
    let total_qty = 0, total_amt = 0;
    (frm.doc.lab_items || []).forEach(row => {
        total_qty += row.qty || 0;
        total_amt += row.amount_before_discount || 0;
    });

    let discount = 0;
    if (frm.doc.custom_discount_mode === "Cash") discount = frm.doc.custom_amount_of_discount || 0;
    if (frm.doc.custom_discount_mode === "Percentage") discount = (total_amt * (frm.doc.custom_percentage_of_discount || 0)) / 100;

    const final = total_amt - discount;
    const rounded = Math.round(final);

    frm.set_value("total_quantity", total_qty);
    frm.set_value("total_amount", final);
    frm.set_value("rounded_total_amount", rounded);
    frm.set_value("saved_amount", discount);
    frm.set_value("total_items", frm.doc.lab_items.length);

    frappe.call({
        method: "health_sil.services.money_in_words_api.money_in_words_api",
        args: { amount: rounded },
        callback: function(r) {
            if (r.message) frm.set_value("amount_in_words", r.message);
        }
    });

    frm.refresh_fields([
        "total_quantity", "total_amount", "rounded_total_amount",
        "saved_amount", "total_items"
    ]);
}

// Global variable to store the current dialog reference
let currentLabTestDialog = null;

function show_lab_tests_dialog(frm) {
    frappe.call({
        method: "health_sil.services.lab_test_api.get_lab_tests_by_bill",
        args: { lab_bill: frm.doc.name },
        callback: function(r) {
            const tests = r.message || [];
            let html = `<div id="lab-tests-container">
                <table class="table table-bordered">
                    <thead>
                        <tr>
                            <th>Test</th>
                            <th>Action</th>
                        </tr>
                    </thead>
                    <tbody>`;

            tests.forEach((test, index) => {
                let actionBtn = '';
                if (!test.name) {
                    actionBtn = `<button class="btn btn-primary" onclick="frappe.throw('No Lab Test Found')">Add Result</button>`;
                } else if (test.docstatus === 1) {
                    actionBtn = `<span class="text-success">${test.name}</span>
                        <button class="btn btn-secondary ml-2" onclick="window.open('/printview?doctype=Lab Test&name=${test.name}&trigger_print=1')">Print</button>`;
                } else {
                    actionBtn = `<button class="btn btn-warning enter-result-btn" data-test-id="${test.name}" data-template="${test.template}" data-index="${index}">Enter Result</button>`;
                }
                html += `<tr id="test-row-${index}">
                    <td>${test.template}</td>
                    <td id="action-cell-${index}">${actionBtn}</td>
                </tr>`;
            });

            html += `</tbody></table></div>`;

            currentLabTestDialog = new frappe.ui.Dialog({
                title: 'Lab Tests for This Bill',
                fields: [{ fieldtype: 'HTML', fieldname: 'lab_test_table', options: html }]
            });

            currentLabTestDialog.show();

            // Bind click events
            setTimeout(() => {
                currentLabTestDialog.$wrapper.find('.enter-result-btn').off('click').on('click', function () {
                    const lab_test_id = $(this).data('test-id');
                    const template = $(this).data('template');
                    const index = $(this).data('index');
                    open_result_dialog(lab_test_id, template, index, frm);
                });
            }, 300);
        }
    });
}

function open_result_dialog(lab_test_id, template, rowIndex, frm) {
    frappe.call({
        method: "health_sil.services.lab_test_api.get_lab_test_result_fields",
        args: { lab_test_id },
        callback: function(r) {
            let html = `<table class="table table-bordered">
                <thead>
                    <tr>
                        <th>Test</th>
                        <th>Result</th>
                        <th>UOM</th>
                        <th>Normal Range</th>
                    </tr>
                </thead>
                <tbody>`;

            r.message.rows.forEach(row => {
                html += `<tr>
                    <td>${row.lab_test_name}</td>
                    <td><input class="form-control" name="result_value_${row.name}" /></td>
                    <td>${row.uom}</td>
                    <td>${row.normal_range}</td>
                </tr>`;
            });
            html += `</tbody></table>`;

            const resultDialog = new frappe.ui.Dialog({
                title: `Enter Results - ${template}`,
                fields: [{ fieldtype: "HTML", fieldname: "results_table", options: html }],
                primary_action_label: "Submit Results",
                primary_action: () => {
                    const results = {};
                    r.message.rows.forEach(row => {
                        const value = resultDialog.$wrapper.find(`[name=result_value_${row.name}]`).val();
                        if (!value || value.trim() === '') {
                            frappe.throw(`Please enter result for ${row.lab_test_name}`);
                            return;
                        }
                        results[row.name] = value;
                    });

                    const confirmDialog = new frappe.ui.Dialog({
                        title: "Confirm Submission",
                        fields: [{ 
                            fieldtype: "HTML", 
                            options: "<p><strong>Are you sure you want to submit these results?</strong></p><p style='color: #d73e48;'>This action cannot be undone.</p>" 
                        }],
                        primary_action_label: "Yes, Submit",
                        primary_action: () => {
                            // Show loading state by updating button text directly
                            const primaryBtn = confirmDialog.$wrapper.find('.btn-primary');
                            const originalText = primaryBtn.text();
                            primaryBtn.prop('disabled', true).html('<i class="fa fa-spinner fa-spin"></i> Submitting...');

                            frappe.call({
                                method: "health_sil.services.lab_test_api.submit_lab_test_with_results",
                                args: {
                                    lab_test_id: r.message.lab_test_id,
                                    results
                                },
                                callback: function(response) {
                                    if (response.message) {
                                        frappe.msgprint({
                                            title: "Success",
                                            message: "Results submitted successfully!",
                                            indicator: "green"
                                        });

                                        // Close dialogs
                                        confirmDialog.hide();
                                        resultDialog.hide();

                                        // ✅ UPDATE DOM WITHOUT REFRESH
                                        update_test_row_ui(lab_test_id, template, rowIndex, response.message);

                                    } else {
                                        frappe.msgprint({
                                            title: "Error",
                                            message: "Failed to submit results. Please try again.",
                                            indicator: "red"
                                        });
                                        // Reset button state
                                        primaryBtn.prop('disabled', false).text(originalText);
                                    }
                                },
                                error: function() {
                                    frappe.msgprint({
                                        title: "Error",
                                        message: "An error occurred. Please try again.",
                                        indicator: "red"
                                    });
                                    // Reset button state
                                    primaryBtn.prop('disabled', false).text(originalText);
                                }
                            });
                        },
                        secondary_action_label: "Cancel",
                        secondary_action: () => {
                            confirmDialog.hide();
                            resultDialog.show();
                        }
                    });

                    resultDialog.hide();
                    confirmDialog.show();
                }
            });

            resultDialog.show();
        }
    });
}

// ✅ FUNCTION TO UPDATE UI WITHOUT REFRESH
function update_test_row_ui(lab_test_id, template, rowIndex, response_data) {
    if (!currentLabTestDialog || !currentLabTestDialog.$wrapper) {
        console.log("Dialog not found, cannot update UI");
        return;
    }

    // Find the specific row and action cell
    const actionCell = currentLabTestDialog.$wrapper.find(`#action-cell-${rowIndex}`);

    if (actionCell.length === 0) {
        console.log(`Action cell not found for row ${rowIndex}`);
        return;
    }

    // Get the lab test name from response or use the lab_test_id
    const lab_test_name = response_data.name || response_data.lab_test_name || lab_test_id;

    // Create new HTML for submitted status
    const newActionHtml = `
        <span class="text-success" style="font-weight: bold;">
            <i class="fa fa-check-circle"></i> ${lab_test_name}
        </span>
        <button class="btn btn-secondary btn-sm ml-2" 
                onclick="window.open('/printview?doctype=Lab Test&name=${lab_test_name}&trigger_print=1')"
                title="Print Lab Test">
            <i class="fa fa-print"></i> Print
        </button>
    `;

    // Update the DOM
    actionCell.html(newActionHtml);

    // Add a subtle animation to highlight the change
    actionCell.css({
        'background-color': '#d4edda',
        'transition': 'background-color 0.5s ease'
    });

    // Remove the highlight after 2 seconds
    setTimeout(() => {
        actionCell.css('background-color', '');
    }, 2000);

    // Optional: Show a toast notification
    frappe.show_alert({
        message: `<strong>${template}</strong> results submitted successfully!`,
        indicator: 'green'
    }, 5);

    console.log(`Successfully updated UI for test ${lab_test_id} in row ${rowIndex}`);
}

frappe.ui.form.on('Item', {
    custom_mrp_per_purchase_uom: function(frm) {
        calculate_valuation_rate(frm);
    }
});

frappe.ui.form.on('Item Tax', {
	item_tax_template: function(frm, cdt, cdn) {
        calculate_valuation_rate(frm);
    }
});

function calculate_valuation_rate(frm) {
    const mrp = frm.doc.custom_mrp_per_purchase_uom;
    const purchase_uom = frm.doc.purchase_uom;
    const stock_uom = frm.doc.stock_uom;

    if (!mrp || !purchase_uom || !stock_uom || !frm.doc.taxes || frm.doc.taxes.length === 0) return;

    let gst_rate = 0;

    let taxes_data = frm.doc.taxes || [];

    if (taxes_data.length > 0) {
        let tax_template = taxes_data[0].item_tax_template;

        if (tax_template) {
            frappe.call({
                method: 'frappe.client.get_value',
                args: {
                    doctype: "Item Tax Template",
                    fieldname: "gst_rate",
                    filters: { name: tax_template }
                },
                callback: function(res) {
                    let gst_rate = 0;
                    if (res.message && res.message.gst_rate !== undefined) {
                        gst_rate = res.message.gst_rate;
                    }
                    compute_and_set_valuation_rate(frm, gst_rate);
                }
            });
        } else {
            compute_and_set_valuation_rate(frm, 0);
        }
    } else {
        compute_and_set_valuation_rate(frm, 0);
    }
}

function compute_and_set_valuation_rate(frm, gst_rate) {
    const mrp = frm.doc.custom_mrp_per_purchase_uom;
    const purchase_uom = frm.doc.purchase_uom;
    const stock_uom = frm.doc.stock_uom;

    const base_rate = mrp / (1 + (gst_rate / 100));

    // Fetch from global UOM Conversion Factor table
    frappe.call({
        method: "frappe.client.get_list",
        args: {
            doctype: "UOM Conversion Factor",
            filters: {
                from_uom: purchase_uom,
                to_uom: stock_uom
            },
            fields: ["value"]
        },
        callback: function(r) {
            let conversion_factor = 1;
            if (r.message && r.message.length > 0) {
                conversion_factor = r.message[0].value || 1;

                const valuation_rate = base_rate / conversion_factor;
                frm.set_value('valuation_rate', valuation_rate.toFixed(3));

                let new_mrp = mrp / conversion_factor;
                console.log(new_mrp)
                frm.set_value('custom_mrp', new_mrp.toFixed(3));
            } else {
                frappe.msgprint("No UOM conversion found between " + purchase_uom + " and " + stock_uom);
            }
        }
    });
}
